function plural(n, one, few, many){
  const m10 = n%10, m100 = n%100;
  if (m10===1 && m100!==11) return one;
  if (m10>=2 && m10<=4 && (m100<10 || m100>=20)) return few;
  return many;
}

const out = $input.all();
let rows = out[0]?.json;
if (!Array.isArray(rows)) rows = out.map(i => i.json);
rows = (rows || []).filter(Boolean);

const NL = String.fromCharCode(10);
const today = new Date().toLocaleDateString('ru-RU',{
  day:'numeric', month:'long', timeZone:'Europe/Moscow'
});

if (!rows.length) {
  const text = '📅 Итоги недели ('+today+')'+NL+NL+
    'На этой неделе ты не отметил ни одной статьи 👍.'+NL+
    'Лайкай интересное — и в следующее воскресенье покажу, что тебя зацепило.';
  return [{ json: { weeklyText: text } }];
}

const byLink = {};
const kwCount = {};
const srcCount = {};
for (const r of rows) {
  const a = Array.isArray(r.articles) ? r.articles[0] : r.articles;
  if (!a) continue;
  const key = a.link || a.title;
  if (!byLink[key]) byLink[key] = { title:a.title, link:a.link, source:a.source, count:0 };
  byLink[key].count++;
  if (a.source) srcCount[a.source] = (srcCount[a.source]||0)+1;
  for (const kw of (a.keywords||[])) kwCount[kw] = (kwCount[kw]||0)+1;
}

const ranked = Object.values(byLink).sort((x,y) => y.count - x.count);
const totalLikes = rows.length;
const topArticles = ranked.slice(0,5);

const themeOfWeek = Object.entries(kwCount).sort((a,b) => b[1]-a[1])[0];
const topSource   = Object.entries(srcCount).sort((a,b) => b[1]-a[1])[0];

const medals = ['🥇','🥈','🥉'];
const lines = topArticles.map((a,i) => {
  const medal = medals[i] || (i+1)+'.';
  const c = a.count > 1 ? ' ('+a.count+' 👍)' : '';
  return medal+' '+a.title+c+NL+'   → '+a.link;
});

const text = [
  '📅 Итоги недели ('+today+')',
  '',
  'За неделю ты отметил 👍 '+totalLikes+' '+plural(totalLikes,'статью','статьи','статей')+'.',
  themeOfWeek ? '🔑 Тема недели: #'+themeOfWeek[0]+' ('+themeOfWeek[1]+'×)' : '',
  topSource   ? '🌐 Любимый источник: '+topSource[0] : '',
  '',
  '⭐ Что зацепило больше всего:',
  lines.join(NL+NL)
].filter(Boolean).join(NL);

return [{ json: { weeklyText: text } }];
